import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppTab {
  CHAT = 'chat',
  IMAGINE = 'imagine',
  LIVE = 'live'
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  groundingUrls?: { title: string; uri: string }[];
}

export interface GeneratedImage {
  url: string;
  prompt: string;
  timestamp: number;
}

import React, { useState, useEffect } from 'react';
import { AppTab } from './types';
import ChatView from './components/ChatView';
import ImagineView from './components/ImagineView';
import LiveView from './components/LiveView';
import Sidebar from './components/Sidebar';
import Header from './components/Header';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.CHAT);
  const [isSidebarOpen, setSidebarOpen] = useState(true);

  // Responsive sidebar handling
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 768) {
        setSidebarOpen(false);
      } else {
        setSidebarOpen(true);
      }
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        isOpen={isSidebarOpen} 
        toggle={() => setSidebarOpen(!isSidebarOpen)}
      />

      <main className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'md:ml-0' : 'ml-0'}`}>
        <Header activeTab={activeTab} toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} />

        <div className="flex-1 overflow-hidden relative">
          {activeTab === AppTab.CHAT && <ChatView />}
          {activeTab === AppTab.IMAGINE && <ImagineView />}
          {activeTab === AppTab.LIVE && <LiveView />}
        </div>
      </main>
    </div>
  );
};

export default App;

