import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { Message } from '../types';

const ChatView: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: input,
        config: {
          systemInstruction: 'Bạn là trợ lý hỗ trợ khách hàng thông minh của trang web www.gbdesign.online. Nhiệm vụ của bạn là giải đáp các thắc mắc về dịch vụ thiết kế, hỗ trợ kỹ thuật và cung cấp thông tin hữu ích cho khách hàng của GB Design. Hãy luôn trả lời một cách lịch sự, chuyên nghiệp và thân thiện bằng tiếng Việt. Nếu ai đó hỏi bạn là ai, hãy tự tin trả lời: "Tôi là trợ lý ảo chính thức của GB Design".',
          tools: [{ googleSearch: {} }]
        }
      });

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const urls = groundingChunks
        .filter(chunk => chunk.web)
        .map(chunk => ({ title: chunk.web?.title || 'Nguồn tin', uri: chunk.web?.uri || '' }));

      const modelMessage: Message = {
        role: 'model',
        text: response.text || "Xin lỗi, tôi không thể phản hồi lúc này. Vui lòng thử lại sau.",
        timestamp: Date.now(),
        groundingUrls: urls
      };

      setMessages(prev => [...prev, modelMessage]);
    } catch (error) {
      console.error('Chat error:', error);
      setMessages(prev => [...prev, {
        role: 'model',
        text: 'Rất tiếc, đã có lỗi kết nối. Bạn có thể liên hệ trực tiếp qua hotline trên website www.gbdesign.online.',
        timestamp: Date.now()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto px-4">
      <div ref={scrollRef} className="flex-1 overflow-y-auto pt-6 pb-24 space-y-6 scroll-smooth">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-6">
            <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center text-4xl shadow-2xl shadow-blue-600/30">
              <span className="font-black text-white">GB</span>
            </div>
            <div className="space-y-2">
              <h3 className="text-3xl font-bold text-white tracking-tight">GB Design Support</h3>
              <p className="text-slate-400 max-w-md mx-auto leading-relaxed">
                Chào mừng bạn đến với trung tâm hỗ trợ của <strong>www.gbdesign.online</strong>. Tôi là trợ lý ảo sẵn sàng giúp bạn giải đáp mọi thắc mắc.
              </p>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 w-full max-w-lg mt-4">
              {[
                "Các dịch vụ của GB Design là gì?",
                "Làm sao để liên hệ báo giá?",
                "Thời gian hoàn thành dự án?",
                "Xem các mẫu thiết kế mới nhất"
              ].map((suggestion, i) => (
                <button 
                  key={i}
                  onClick={() => { setInput(suggestion); }}
                  className="text-left px-4 py-3 bg-slate-900/50 border border-slate-800 rounded-xl text-sm text-slate-300 hover:bg-slate-800 hover:border-blue-500/50 transition-all"
                >
                  {suggestion}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-5 py-3 shadow-sm ${
              msg.role === 'user' 
                ? 'bg-blue-600 text-white' 
                : 'bg-slate-800/80 border border-slate-700/50 text-slate-100 shadow-xl'
            }`}>
              <div className="whitespace-pre-wrap leading-relaxed">{msg.text}</div>

              {msg.groundingUrls && msg.groundingUrls.length > 0 && (
                <div className="mt-4 pt-4 border-t border-slate-700/50 space-y-2">
                  <p className="text-[10px] uppercase tracking-wider text-slate-400 font-bold">Tham khảo thêm từ web</p>
                  <div className="flex flex-wrap gap-2">
                    {msg.groundingUrls.map((link, lIdx) => (
                      <a 
                        key={lIdx} 
                        href={link.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-xs bg-slate-700/50 hover:bg-slate-700 px-3 py-1 rounded-full text-blue-300 transition-colors inline-block max-w-[200px] truncate"
                      >
                        {link.title}
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-800/80 border border-slate-700/50 rounded-2xl px-5 py-3 flex gap-1.5">
              <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
              <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
              <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-slate-950 via-slate-950/80 to-transparent">
        <form onSubmit={handleSend} className="max-w-4xl mx-auto flex gap-3 p-2 bg-slate-800/80 backdrop-blur-md rounded-2xl border border-slate-700 shadow-2xl focus-within:border-blue-500/50 transition-colors">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Hỏi trợ lý GB Design..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-slate-100 px-4 py-3 placeholder:text-slate-500"
          />
          <button
            type="submit"
            disabled={!input.trim() || isLoading}
            className="p-3 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 disabled:opacity-50 rounded-xl transition-all shadow-lg shadow-blue-600/20 active:scale-95"
          >
            <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </form>
        <p className="text-[10px] text-center text-slate-600 mt-3 uppercase tracking-tighter">Bản quyền thuộc về GB Design © 2024</p>
      </div>
    </div>
  );
};

export default ChatView;

