const StudioView: React.FC = () => {
  const [images, setImages] = useState<GeneratedImage[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);

  // Model Parameters
  const [gender, setGender] = useState<'Nam' | 'Nữ'>('Nữ');
  const [style, setStyle] = useState('Châu Á');
  const [background, setBackground] = useState('Studio phông trắng');
  const [lighting, setLighting] = useState('Ánh sáng Studio mềm mại');
  const [pose, setPose] = useState('Đứng thẳng, nhìn camera');
  const [customPrompt, setCustomPrompt] = useState('');

  const generateModel = async () => {
    setIsGenerating(true);
    try {
      const fullPrompt = `Chụp ảnh chuyên nghiệp 4k, người mẫu ${gender} ${style}, ${pose}, mặt cực kỳ chi tiết, da thật, ánh sáng ${lighting}, bối cảnh ${background}. Chất lượng studio, tiêu cự 85mm, f/1.8. ${customPrompt}`;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview', // Sử dụng model Pro cho chất lượng cao nhất
        contents: { parts: [{ text: fullPrompt }] },
        config: {
          imageConfig: { aspectRatio: "3:4" }
        }
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          const url = `data:image/png;base64,${part.inlineData.data}`;
          setImages(prev => [{ url, prompt: fullPrompt, params: { gender, style, background }, timestamp: Date.now() }, ...prev]);
          break;
        }
      }
    } catch (error) {
      console.error('Studio Error:', error);
      alert('Không thể tạo mẫu. Vui lòng thử lại.');
    } finally {
      setIsGenerating(false);
