                className={`py-2.5 rounded-xl text-xs font-bold border transition-all ${gender === g ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'}`}
              >
                {g}
              </button>
            ))}
          </div>
          <select 
            value={style}
            onChange={(e) => setStyle(e.target.value)}
            className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 focus:ring-1 focus:ring-blue-500 outline-none"
          >
            <option>Châu Á</option>
            <option>Châu Âu</option>
            <option>Châu Mỹ</option>
            <option>Châu Phi</option>
          </select>
        </div>

        <div className="space-y-4">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Bối cảnh & Ánh sáng</label>
          <select 
            value={background}
            onChange={(e) => setBackground(e.target.value)}
            className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 outline-none"
          >
            <option>Studio phông trắng</option>
            <option>Studio phông xám tối</option>
            <option>Đường phố hiện đại</option>
            <option>Quán Cafe phong cách</option>
            <option>Bãi biển hoàng hôn</option>
            <option>Văn phòng làm việc</option>
          </select>
          <select 
