import React, { useState } from 'react';
import { GoogleGenAI } from '@google/genai';

const ProductEditor: React.FC = () => {
  const [productImage, setProductImage] = useState<string | null>(null);
  const [baseModel, setBaseModel] = useState<string | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'product' | 'model') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'product') setProductImage(reader.result as string);
        else setBaseModel(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const processTryOn = async () => {
    if (!productImage || !baseModel) return;

    setIsProcessing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image', // Model này tối ưu cho việc chỉnh sửa ảnh nhanh
        contents: {
          parts: [
            { inlineData: { data: baseModel.split(',')[1], mimeType: 'image/png' } },
            { inlineData: { data: productImage.split(',')[1], mimeType: 'image/png' } },
            { text: "Hãy thực hiện Virtual Try-on: Giữ nguyên khuôn mặt và dáng người mẫu trong ảnh đầu tiên, nhưng thay bộ đồ họ đang mặc bằng sản phẩm trong ảnh thứ hai một cách chân thực nhất. Ánh sáng và nếp nhăn vải phải khớp với tư thế người mẫu." }
          ]
        }
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          setResultImage(`data:image/png;base64,${part.inlineData.data}`);
          break;
        }
      }
    } catch (error) {
      console.error('Try-on Error:', error);
      alert('Quá trình thử đồ thất bại. Vui lòng kiểm tra lại ảnh đầu vào.');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="h-full flex flex-col p-8 bg-slate-950 overflow-y-auto">
      <div className="max-w-6xl mx-auto w-full space-y-12">
        <div className="text-center space-y-2">
          <h2 className="text-3xl font-black text-white italic tracking-tighter uppercase">Virtual Try-On Studio</h2>
          <p className="text-slate-500 text-sm font-medium uppercase tracking-widest">Tải lên sản phẩm và người mẫu để kết hợp tự động</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Step 1: Uploads */}
          <div className="space-y-6">
