import React, { useState } from 'react';
import { GoogleGenAI } from '@google/genai';
import { GeneratedImage } from '../types';

const StudioView: React.FC = () => {
  const [images, setImages] = useState<GeneratedImage[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showKeyPicker, setShowKeyPicker] = useState(false);

  // Model Parameters
  const [gender, setGender] = useState<'Nam' | 'Nữ'>('Nữ');
  const [style, setStyle] = useState('Châu Á');
  const [background, setBackground] = useState('Studio phông trắng');
  const [lighting, setLighting] = useState('Ánh sáng Studio mềm mại');
  const [pose, setPose] = useState('Đứng thẳng, nhìn camera');
  const [customPrompt, setCustomPrompt] = useState('');

  const handleOpenKeyPicker = async () => {
    if (window.aistudio && window.aistudio.openSelectKey) {
      await window.aistudio.openSelectKey();
      setShowKeyPicker(false);
      // Giả định chọn thành công và thử lại
      generateModel();
    } else {
      alert("Tính năng chọn API Key không khả dụng trong môi trường này.");
    }
  };

  const generateModel = async () => {
    // Kiểm tra quyền truy cập cho model Pro
    if (window.aistudio && !(await window.aistudio.hasSelectedApiKey())) {
      setShowKeyPicker(true);
      return;
    }

    setIsGenerating(true);
    try {
      const fullPrompt = `Chụp ảnh chuyên nghiệp 4k, người mẫu ${gender} ${style}, ${pose}, mặt cực kỳ chi tiết, da thật, ánh sáng ${lighting}, bối cảnh ${background}. Chất lượng studio, tiêu cự 85mm, f/1.8. ${customPrompt}`;

      // Khởi tạo instance mới để lấy key cập nhật nhất
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: { parts: [{ text: fullPrompt }] },
        config: {
          imageConfig: { 
            aspectRatio: "3:4",
            imageSize: "1K" // Đảm bảo kích thước chuẩn cho model Pro
          }
        }
      });

      let hasFoundImage = false;
      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          const url = `data:image/png;base64,${part.inlineData.data}`;
          setImages(prev => [{ url, prompt: fullPrompt, params: { gender, style, background }, timestamp: Date.now() }, ...prev]);
          hasFoundImage = true;
          break;
        }
      }

      if (!hasFoundImage) {
        throw new Error("Không nhận được dữ liệu hình ảnh từ mô hình.");
      }

    } catch (error: any) {
      console.error('Studio Error:', error);
      if (error.message?.includes("403") || error.message?.includes("PERMISSION_DENIED") || error.message?.includes("not found")) {
        setShowKeyPicker(true);
      } else {
        alert('Không thể tạo mẫu. Lỗi: ' + (error.message || "Vui lòng thử lại."));
      }
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="h-full flex flex-col md:flex-row overflow-hidden bg-slate-950">
      {/* Modal chọn API Key khi lỗi 403 */}
      {showKeyPicker && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/90 backdrop-blur-md p-4">
          <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2.5rem] max-w-md w-full text-center space-y-6 shadow-2xl">
            <div className="w-20 h-20 bg-blue-600/20 rounded-3xl flex items-center justify-center mx-auto text-blue-500">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
              </svg>
            </div>
            <div className="space-y-2">
              <h3 className="text-2xl font-black text-white">Yêu cầu xác thực Pro</h3>
              <p className="text-slate-400 text-sm leading-relaxed">
                Để sử dụng model <strong>Gemini 3 Pro Image</strong>, bạn cần sử dụng API Key từ một dự án Google Cloud đã bật tính phí (Paid Project).
              </p>
              <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="text-xs text-blue-400 hover:underline">Tìm hiểu về biểu phí và thanh toán</a>
            </div>
            <div className="flex flex-col gap-3 pt-4">
              <button 
                onClick={handleOpenKeyPicker}
                className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white font-black rounded-2xl shadow-xl shadow-blue-600/20 transition-all active:scale-95"
              >
                CHỌN API KEY CỦA BẠN
              </button>
              <button 
                onClick={() => setShowKeyPicker(false)}
                className="w-full py-3 text-slate-500 text-xs font-bold hover:text-slate-300"
              >
                ĐỂ SAU
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Control Panel */}
      <div className="w-full md:w-80 border-r border-slate-800 bg-slate-900/30 p-6 overflow-y-auto space-y-8 scrollbar-hide">
        <div className="space-y-4">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Đặc điểm người mẫu</label>
          <div className="grid grid-cols-2 gap-2">
            {['Nữ', 'Nam'].map(g => (
              <button 
                key={g}
                onClick={() => setGender(g as any)}
                className={`py-2.5 rounded-xl text-xs font-bold border transition-all ${gender === g ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'}`}
              >
                {g}
              </button>
            ))}
          </div>
          <select 
            value={style}
            onChange={(e) => setStyle(e.target.value)}
            className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 focus:ring-1 focus:ring-blue-500 outline-none"
          >
            <option>Châu Á</option>
            <option>Châu Âu</option>
            <option>Châu Mỹ</option>
            <option>Châu Phi</option>
          </select>
        </div>

        <div className="space-y-4">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Bối cảnh & Ánh sáng</label>
          <select 
            value={background}
            onChange={(e) => setBackground(e.target.value)}
            className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 outline-none"
          >
            <option>Studio phông trắng</option>
            <option>Studio phông xám tối</option>
            <option>Đường phố hiện đại</option>
            <option>Quán Cafe phong cách</option>
            <option>Bãi biển hoàng hôn</option>
            <option>Văn phòng làm việc</option>
          </select>
          <select 
            value={lighting}
            onChange={(e) => setLighting(e.target.value)}
            className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 outline-none"
          >
            <option>Ánh sáng Studio mềm mại</option>
            <option>Ánh sáng tự nhiên</option>
            <option>Ánh sáng Neon rực rỡ</option>
            <option>Ánh sáng High-key (Sáng mạnh)</option>
            <option>Ánh sáng Low-key (Bí ẩn)</option>
          </select>
        </div>

        <div className="space-y-4">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Tạo dáng (Pose)</label>
          <select 
            value={pose}
            onChange={(e) => setPose(e.target.value)}
            className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 outline-none"
          >
            <option>Đứng thẳng, nhìn camera</option>
            <option>Nhìn nghiêng 45 độ</option>
            <option>Ngồi ghế sang trọng</option>
            <option>Đang bước đi tự nhiên</option>
            <option>Cầm sản phẩm (mỹ phẩm/điện thoại)</option>
          </select>
        </div>

        <div className="space-y-4">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mô tả thêm (Tùy chọn)</label>
          <textarea 
            value={customPrompt}
            onChange={(e) => setCustomPrompt(e.target.value)}
            placeholder="Ví dụ: Mặc áo sơ mi trắng, tóc đuôi ngựa..."
            className="w-full h-24 bg-slate-800 border-slate-700 rounded-xl p-4 text-xs text-slate-200 resize-none outline-none focus:border-blue-500/50"
          />
        </div>

        <button
          onClick={generateModel}
          disabled={isGenerating}
          className="w-full py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 disabled:opacity-50 text-white font-black rounded-2xl shadow-xl shadow-blue-600/20 flex items-center justify-center gap-3 transition-all active:scale-95"
        >
          {isGenerating ? (
            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
          ) : (
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
            </svg>
          )}
          <span>TẠO NGƯỜI MẪU</span>
        </button>
      </div>

      {/* Main Canvas */}
      <div className="flex-1 p-8 overflow-y-auto">
        {images.length === 0 && !isGenerating ? (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-6">
            <div className="w-32 h-32 bg-slate-900 rounded-full flex items-center justify-center border border-slate-800">
               <svg className="w-16 h-16 text-slate-700" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
               </svg>
            </div>
            <div className="max-w-xs">
              <h3 className="text-lg font-bold text-white">Chưa có bản mẫu nào</h3>
              <p className="text-sm text-slate-500 mt-2">Thiết lập các thông số bên trái và nhấn nút "Tạo" để bắt đầu quy trình nhiếp ảnh AI.</p>
