        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pb-12">
            {isGenerating && (
               <div className="aspect-[3/4] bg-slate-900 border border-slate-800 border-dashed rounded-3xl flex flex-col items-center justify-center space-y-4 animate-pulse">
