            {images.map((img, idx) => (
              <div key={idx} className="group relative bg-slate-900 rounded-3xl overflow-hidden border border-slate-800 shadow-2xl transition-all hover:-translate-y-1">
                <img src={img.url} alt="AI Model" className="w-full h-auto object-cover" />
                <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-all p-6 flex flex-col justify-end">
                   <div className="flex gap-2">
                      <button 
                        onClick={() => {
                          const link = document.createElement('a');
                          link.href = img.url;
                          link.download = `gb-model-${idx}.png`;
                          link.click();
                        }}
