import { GoogleGenAI } from '@google/genai';
import React, { useState } from 'react';

const ProductEditor: React.FC = () => {
  const [productImage, setProductImage] = useState<string | null>(null);
  const [baseModel, setBaseModel] = useState<string | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'product' | 'model') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'product') setProductImage(reader.result as string);
        else setBaseModel(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const processTryOn = async () => {
    if (!productImage || !baseModel) return;

    setIsProcessing(true);
    try {
      // Re-initialize to ensure current key is used
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: baseModel.split(',')[1], mimeType: 'image/png' } },
            { inlineData: { data: productImage.split(',')[1], mimeType: 'image/png' } },
            { text: "Virtual Try-on task: Keep the exact facial features, skin tone, and body pose of the model in the FIRST image. Replace their current outfit with the product in the SECOND image. Ensure clothing folds, shadows, and fabric texture align perfectly with the model's anatomy and studio lighting. Output a high-resolution, professional commercial image." }
          ]
        }
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          setResultImage(`data:image/png;base64,${part.inlineData.data}`);
          break;
        }
      }
    } catch (error: any) {
      console.error('Try-on Error:', error);
      if (error.message?.includes("403")) {
          if (window.aistudio && window.aistudio.openSelectKey) {
            await window.aistudio.openSelectKey();
          } else {
            alert("Lỗi xác thực (403). Vui lòng kiểm tra API Key của bạn.");
          }
      } else {
        alert('Quá trình thử đồ thất bại. Hãy thử lại với ảnh rõ nét hơn.');
      }
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="h-full flex flex-col p-8 bg-slate-950 overflow-y-auto">
      <div className="max-w-6xl mx-auto w-full space-y-12">
        <div className="text-center space-y-4">
          <h2 className="text-4xl font-black text-white italic tracking-tighter uppercase">Virtual Try-On Studio</h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.3em]">AI-Powered Commercial Fashion Editor</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="space-y-8">
            <div className="p-8 bg-slate-900/40 rounded-[2.5rem] border border-slate-800 space-y-5 shadow-inner">
              <div className="flex items-center justify-between">
                <label className="text-[10px] font-black text-blue-400 uppercase tracking-widest">1. Sản phẩm mục tiêu</label>
                {productImage && <button onClick={() => setProductImage(null)} className="text-[10px] font-bold text-slate-600 hover:text-red-400 uppercase">Xóa</button>}
              </div>
              <div 
                className={`relative aspect-video rounded-3xl border-2 border-dashed transition-all flex items-center justify-center overflow-hidden group cursor-pointer ${productImage ? 'border-emerald-500/30' : 'border-slate-800 hover:border-blue-500/40'}`}
                onClick={() => document.getElementById('product-up')?.click()}
              >
                {productImage ? (
                  <img src={productImage} className="w-full h-full object-contain p-4" alt="Product" />
                ) : (
                  <div className="text-center space-y-3">
                    <div className="w-12 h-12 bg-slate-800 rounded-2xl flex items-center justify-center mx-auto text-slate-600 group-hover:text-blue-500 group-hover:scale-110 transition-all">
                       <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                       </svg>
                    </div>
                    <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Tải ảnh quần áo/túi xách</span>
                  </div>
                )}
                <input id="product-up" type="file" className="hidden" onChange={(e) => handleFileUpload(e, 'product')} />
              </div>
            </div>

            <div className="p-8 bg-slate-900/40 rounded-[2.5rem] border border-slate-800 space-y-5 shadow-inner">
              <div className="flex items-center justify-between">
                <label className="text-[10px] font-black text-blue-400 uppercase tracking-widest">2. Người mẫu cơ sở</label>
                {baseModel && <button onClick={() => setBaseModel(null)} className="text-[10px] font-bold text-slate-600 hover:text-red-400 uppercase">Xóa</button>}
              </div>
              <div 
                className={`relative aspect-video rounded-3xl border-2 border-dashed transition-all flex items-center justify-center overflow-hidden group cursor-pointer ${baseModel ? 'border-emerald-500/30' : 'border-slate-800 hover:border-blue-500/40'}`}
                onClick={() => document.getElementById('model-up')?.click()}
              >
                {baseModel ? (
                  <img src={baseModel} className="w-full h-full object-contain p-4" alt="Model" />
                ) : (
                  <div className="text-center space-y-3">
                    <div className="w-12 h-12 bg-slate-800 rounded-2xl flex items-center justify-center mx-auto text-slate-600 group-hover:text-blue-500 group-hover:scale-110 transition-all">
                       <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                       </svg>
                    </div>
                    <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Tải người mẫu của bạn</span>
                  </div>
                )}
                <input id="model-up" type="file" className="hidden" onChange={(e) => handleFileUpload(e, 'model')} />
              </div>
            </div>

            <button
              onClick={processTryOn}
              disabled={!productImage || !baseModel || isProcessing}
              className="w-full py-6 bg-white text-black font-black rounded-[1.5rem] shadow-2xl hover:bg-slate-200 disabled:bg-slate-900 disabled:text-slate-700 disabled:opacity-50 transition-all active:scale-95 uppercase tracking-widest text-xs"
            >
              {isProcessing ? 'AI ĐANG LỒNG GHÉP...' : 'BẮT ĐẦU KẾT HỢP (RENDER)'}
            </button>
          </div>

          <div className="flex flex-col">
            <div className="flex-1 bg-slate-900/60 border border-slate-800 rounded-[3rem] overflow-hidden relative group min-h-[500px] shadow-2xl ring-1 ring-white/5">
              {resultImage ? (
                <>
                  <img src={resultImage} className="w-full h-full object-cover" alt="Result" />
                  <div className="absolute top-8 right-8 flex gap-3 opacity-0 group-hover:opacity-100 transition-all">
                     <button className="px-6 py-3 bg-white text-black rounded-2xl font-black text-[10px] shadow-2xl uppercase tracking-widest">Tải xuống 4K</button>
                  </div>
                </>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-6">
                  {isProcessing ? (
                    <>
                      <div className="relative">
                        <div className="w-20 h-20 border-4 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin"></div>
                        <div className="absolute inset-0 flex items-center justify-center">
                           <svg className="w-8 h-8 text-emerald-500 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                           </svg>
                        </div>
                      </div>
                      <div className="space-y-2">
                        <p className="text-xs text-white font-black uppercase tracking-widest">Đang tính toán cấu trúc vải...</p>
                        <p className="text-[10px] text-slate-500 uppercase font-bold">Xử lý trí tuệ nhân tạo GB Studio</p>
                      </div>
                    </>
                  ) : (
                    <>
                      <div className="w-24 h-24 bg-slate-800/30 rounded-[2rem] flex items-center justify-center text-slate-700 border border-slate-800 shadow-inner">
                         <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                         </svg>
                      </div>
                      <div className="space-y-2">
                        <h4 className="text-sm font-bold text-slate-300 uppercase tracking-widest">Kết quả Render</h4>
