import { RobloxGift } from '../types';

const GIFTS: RobloxGift[] = [
  { id: '1', name: 'Gói Cơ Bản', amount: '400', type: 'robux', image: '💰', rarity: 'common' },
  { id: '2', name: 'Gói Phổ Biến', amount: '800', type: 'robux', image: '💎', rarity: 'common' },
