  { id: '4', name: 'Gói Huyền Thoại', amount: '10000', type: 'robux', image: '🔥', rarity: 'legendary' },
  { id: '5', name: 'Blox Fruit: Leopard', amount: 'Item', type: 'item', image: '🐆', rarity: 'legendary' },
  { id: '6', name: 'PS99: Huge Pet', amount: 'Item', type: 'item', image: '🐱', rarity: 'rare' },
];

const GiftShop: React.FC = () => {
  const [username, setUsername] = useState('');
  const [selectedGift, setSelectedGift] = useState<RobloxGift | null>(null);
  const [step, setStep] = useState<'form' | 'processing' | 'success'>('form');
  const [progress, setProgress] = useState(0);
  const [statusText, setStatusText] = useState('');

  const handleClaim = () => {
    if (!username || !selectedGift) return;

    setStep('processing');
    const steps = [
      "Đang kết nối tới máy chủ Roblox...",
      `Tìm kiếm người dùng: ${username}...`,
      "Đã tìm thấy tài khoản! Đang kiểm tra vùng dữ liệu...",
      `Đang chuẩn bị phần quà: ${selectedGift.name}...`,
      "Đang thực hiện mã hóa bảo mật (SSL)...",
      "Đang hoàn tất quá trình chuyển đổi...",
      "Thành công! Chờ xác minh cuối cùng."
    ];

    let currentStep = 0;
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setStep('success');
          return 100;
        }

        if (prev % 15 === 0 && currentStep < steps.length) {
            setStatusText(steps[currentStep]);
            currentStep++;
        }
        return prev + 1;
      });
    }, 50);
  };

  return (
    <div className="h-full overflow-y-auto p-8 scrollbar-hide">
      <div className="max-w-5xl mx-auto space-y-12 pb-24">

        {step === 'form' && (
          <div className="animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="text-center space-y-4 mb-12">
               <h2 className="text-5xl font-black text-white italic tracking-tighter uppercase">NHẬN QUÀ MIỄN PHÍ</h2>
               <p className="text-slate-500 font-bold uppercase tracking-[0.3em] text-xs">Sự kiện độc quyền dành cho cộng đồng Roblox</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
              {/* Username Input */}
              <div className="lg:col-span-1 space-y-8">
                 <div className="p-8 bg-white/5 rounded-[2.5rem] border border-white/10 space-y-6 shadow-2xl">
                    <label className="text-[10px] font-black text-red-500 uppercase tracking-widest">Bước 1: Nhập tài khoản</label>
                    <div className="relative">
                       <input 
                         type="text"
                         value={username}
                         onChange={(e) => setUsername(e.target.value)}
                         placeholder="Roblox Username"
                         className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl px-6 py-5 text-white font-bold focus:border-red-600 focus:ring-4 focus:ring-red-600/10 outline-none transition-all placeholder:text-slate-700"
                       />
                       <div className="absolute right-4 top-1/2 -translate-y-1/2">
                          <svg className={`w-6 h-6 ${username.length > 2 ? 'text-green-500' : 'text-slate-800'}`} fill="currentColor" viewBox="0 0 20 20">
                            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                          </svg>
                       </div>
                    </div>
                    <p className="text-[10px] text-slate-500 font-medium italic leading-relaxed">
                      * Đảm bảo tên người dùng chính xác. Chúng tôi không yêu cầu mật khẩu.
                    </p>
                 </div>

                 <button 
                   onClick={handleClaim}
                   disabled={!username || !selectedGift}
                   className="w-full py-6 bg-gradient-to-r from-red-600 to-orange-600 hover:from-red-500 hover:to-orange-500 disabled:from-slate-800 disabled:to-slate-800 disabled:opacity-50 text-white font-black rounded-3xl shadow-[0_20px_40px_rgba(220,38,38,0.2)] transition-all active:scale-95 uppercase tracking-widest text-sm"
                 >
                   XÁC NHẬN NHẬN QUÀ
                 </button>
              </div>

              {/* Gift Grid */}
              <div className="lg:col-span-2 space-y-6">
                <label className="text-[10px] font-black text-red-500 uppercase tracking-widest ml-4">Bước 2: Chọn phần quà</label>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                  {GIFTS.map((gift) => (
                    <button
                      key={gift.id}
                      onClick={() => setSelectedGift(gift)}
                      className={`relative group p-6 rounded-[2rem] border transition-all duration-500 flex flex-col items-center text-center space-y-4 overflow-hidden ${
                        selectedGift?.id === gift.id 
                          ? 'bg-red-600/10 border-red-600 shadow-[0_0_30px_rgba(220,38,38,0.15)] scale-[1.02]' 
                          : 'bg-white/5 border-white/5 hover:border-white/20 hover:bg-white/[0.08]'
                      }`}
                    >
                      <div className="text-5xl group-hover:scale-110 transition-transform duration-500 drop-shadow-2xl">{gift.image}</div>
                      <div className="space-y-1">
                        <div className="text-xs font-black text-white uppercase tracking-tighter">{gift.name}</div>
                        <div className="text-[10px] font-black text-red-500 uppercase">{gift.amount} {gift.type === 'robux' ? 'Robux' : ''}</div>
                      </div>

                      {gift.rarity === 'legendary' && (
                        <div className="absolute top-3 right-3">
                           <div className="w-2 h-2 bg-yellow-500 rounded-full animate-ping"></div>
                        </div>
                      )}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 'processing' && (
          <div className="flex flex-col items-center justify-center min-h-[500px] space-y-12 animate-in zoom-in duration-500">
            <div className="relative w-64 h-64">
               {/* Outer ring */}
               <div className="absolute inset-0 border-4 border-white/5 rounded-full"></div>
               {/* Progress ring */}
               <svg className="absolute inset-0 w-full h-full -rotate-90">
                  <circle
                    cx="128"
                    cy="128"
                    r="124"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="8"
                    strokeDasharray={779}
                    strokeDashoffset={779 - (779 * progress) / 100}
                    className="text-red-600 transition-all duration-300 ease-out"
                  />
               </svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center space-y-2">
                  <span className="text-6xl font-black text-white">{progress}%</span>
                  <span className="text-[10px] font-black text-red-500 uppercase tracking-widest">Đang tải</span>
               </div>
            </div>

            <div className="text-center space-y-4 max-w-md">
               <h3 className="text-xl font-black text-white uppercase tracking-tighter animate-pulse">{statusText}</h3>
               <div className="flex gap-1 justify-center">
                  {[1,2,3,4,5].map(i => (
                    <div key={i} className="w-1.5 h-1.5 bg-red-600 rounded-full animate-bounce" style={{ animationDelay: `${i * 100}ms` }}></div>
                  ))}
               </div>
            </div>
          </div>
        )}

        {step === 'success' && (
          <div className="flex flex-col items-center justify-center min-h-[500px] space-y-8 animate-in zoom-in duration-700">
