import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { Message } from '../types';

const ChatView: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: input,
        config: {
          systemInstruction: `Bạn là 'Roblox Expert GPT' - Chuyên gia hàng đầu về Roblox.
          NHIỆM VỤ:
          1. Tư vấn cho người dùng cách nhận quà, Robux miễn phí từ hệ thống một cách an toàn.
          2. Hướng dẫn mẹo chơi các game hot như Blox Fruits, Pet Simulator 99, BedWars.
          3. Giọng điệu: Trẻ trung, năng động, sử dụng ngôn ngữ game thủ (ví dụ: 'Chào pro!', 'Gắt quá!', 'Cày cuốc thôi!').
          4. Luôn khuyến khích người dùng tham gia các sự kiện trong tab 'Kho Quà Tặng' của ứng dụng.
          5. Nếu người dùng hỏi về lừa đảo, hãy khẳng định hệ thống của chúng tôi là uy tín và không yêu cầu mật khẩu.`,
        }
      });

      const modelMessage: Message = {
        role: 'model',
        text: response.text || "Máy chủ Roblox đang bận xử lý, pro thử lại sau nhé!",
        timestamp: Date.now(),
      };

      setMessages(prev => [...prev, modelMessage]);
    } catch (error) {
      console.error('Chat error:', error);
      setMessages(prev => [...prev, {
        role: 'model',
        text: 'Kết nối mạng yếu quá, pro kiểm tra lại wifi xem sao!',
        timestamp: Date.now()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto px-4 relative">
      <div ref={scrollRef} className="flex-1 overflow-y-auto pt-6 pb-28 space-y-6 scrollbar-hide">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-6">
            <div className="w-24 h-24 bg-gradient-to-br from-red-600 to-red-400 rounded-[2rem] flex items-center justify-center text-4xl shadow-2xl rotate-3">
              🤖
            </div>
            <div className="space-y-3">
              <h3 className="text-3xl font-black text-white italic uppercase tracking-tighter">ROBLOX EXPERT AI</h3>
              <p className="text-slate-500 max-w-sm mx-auto leading-relaxed font-bold uppercase text-[10px] tracking-widest">
                Hỏi tôi bất cứ điều gì về Robux, Blox Fruits hoặc cách nhận quà!
              </p>
            </div>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
            <div className={`max-w-[85%] rounded-[2rem] px-8 py-5 shadow-2xl ${
              msg.role === 'user' 
                ? 'bg-red-600 text-white font-bold' 
                : 'bg-white/5 border border-white/10 text-slate-100 font-medium'
            }`}>
              <div className="whitespace-pre-wrap leading-relaxed text-sm">{msg.text}</div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white/5 border border-white/10 rounded-2xl px-6 py-3 flex gap-2">
              <div className="w-2 h-2 bg-red-600 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-red-600 rounded-full animate-bounce delay-100"></div>
              <div className="w-2 h-2 bg-red-600 rounded-full animate-bounce delay-200"></div>
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-[#0a0a0c] via-[#0a0a0c]/90 to-transparent">
        <form onSubmit={handleSend} className="max-w-4xl mx-auto flex gap-3 p-2 bg-white/5 backdrop-blur-3xl rounded-[2rem] border border-white/10 shadow-2xl focus-within:border-red-600/50 transition-all">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Hỏi chuyên gia Roblox ngay..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-white px-6 py-4 placeholder:text-slate-700 font-bold text-sm"
          />
          <button
            type="submit"
            disabled={!input.trim() || isLoading}
            className="px-8 bg-red-600 hover:bg-red-500 disabled:bg-slate-800 disabled:opacity-50 rounded-2xl transition-all shadow-xl active:scale-95 group"
          >
            <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatView;

