import React, { useState, useRef } from 'react';
import { RobloxGift } from '../types';

const INITIAL_GIFTS: RobloxGift[] = [
  { id: '1', name: 'Gói Cơ Bản', amount: '400', type: 'robux', image: '💰', rarity: 'common' },
  { id: '2', name: 'Gói Phổ Biến', amount: '800', type: 'robux', image: '💎', rarity: 'common' },
  { id: '3', name: 'Gói Cao Cấp', amount: '1700', type: 'robux', image: '👑', rarity: 'rare' },
  { id: '4', name: 'Gói Huyền Thoại', amount: '10000', type: 'robux', image: '🔥', rarity: 'legendary' },
  { id: '5', name: 'Blox Fruit: Leopard', amount: 'Item', type: 'item', image: '🐆', rarity: 'legendary' },
  { id: '6', name: 'PS99: Huge Pet', amount: 'Item', type: 'item', image: '🐱', rarity: 'rare' },
];

const GiftShop: React.FC = () => {
  const [username, setUsername] = useState('');
  const [gifts, setGifts] = useState<RobloxGift[]>(INITIAL_GIFTS);
  const [selectedGift, setSelectedGift] = useState<RobloxGift | null>(null);
  const [step, setStep] = useState<'form' | 'processing' | 'success'>('form');
  const [progress, setProgress] = useState(0);
  const [statusText, setStatusText] = useState('');
  const [editingGiftId, setEditingGiftId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleClaim = () => {
    if (!username || !selectedGift) return;

    setStep('processing');
    const steps = [
      "Đang kết nối tới máy chủ Roblox...",
      `Tìm kiếm người dùng: ${username}...`,
      "Đã tìm thấy tài khoản! Đang kiểm tra vùng dữ liệu...",
      `Đang chuẩn bị phần quà: ${selectedGift.name}...`,
      "Đang thực hiện mã hóa bảo mật (SSL)...",
      "Đang hoàn tất quá trình chuyển đổi...",
      "Thành công! Chờ xác minh cuối cùng."
    ];

    let currentStep = 0;
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setStep('success');
          return 100;
        }

        if (prev % 15 === 0 && currentStep < steps.length) {
            setStatusText(steps[currentStep]);
            currentStep++;
        }
        return prev + 1;
      });
    }, 50);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, giftId: string) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setGifts(prev => prev.map(g => 
          g.id === giftId ? { ...g, image: reader.result as string } : g
        ));
      };
      reader.readAsDataURL(file);
    }
  };

  const updateGiftName = (id: string, newName: string) => {
    setGifts(prev => prev.map(g => g.id === id ? { ...g, name: newName } : g));
  };

  const updateGiftAmount = (id: string, newAmount: string) => {
    setGifts(prev => prev.map(g => g.id === id ? { ...g, amount: newAmount } : g));
  };

  return (
    <div className="h-full overflow-y-auto p-8 scrollbar-hide">
      <div className="max-w-6xl mx-auto space-y-12 pb-24">

        {step === 'form' && (
          <div className="animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="text-center space-y-4 mb-12">
               <h2 className="text-5xl font-black text-white italic tracking-tighter uppercase">KHO QUÀ TÙY CHỈNH</h2>
               <p className="text-slate-500 font-bold uppercase tracking-[0.3em] text-xs">Cấu hình quà tặng và nhận ngay Robux</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-10">
              {/* Left Column: Form & Config */}
              <div className="lg:col-span-1 space-y-6">
                 <div className="p-6 bg-white/5 rounded-[2rem] border border-white/10 space-y-6 shadow-2xl">
                    <label className="text-[10px] font-black text-red-500 uppercase tracking-widest">Tài khoản nhận quà</label>
                    <div className="relative">
                       <input 
                         type="text"
                         value={username}
                         onChange={(e) => setUsername(e.target.value)}
                         placeholder="Roblox Username"
                         className="w-full bg-[#0a0a0c] border border-white/10 rounded-xl px-4 py-4 text-white font-bold focus:border-red-600 outline-none transition-all placeholder:text-slate-700 text-sm"
                       />
                    </div>
                 </div>

                 <button 
                   onClick={handleClaim}
                   disabled={!username || !selectedGift}
                   className="w-full py-5 bg-gradient-to-r from-red-600 to-orange-600 hover:from-red-500 hover:to-orange-500 disabled:from-slate-800 disabled:to-slate-800 disabled:opacity-50 text-white font-black rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xs"
                 >
                   XÁC NHẬN NHẬN QUÀ
                 </button>

                 <div className="p-5 bg-blue-500/5 border border-blue-500/10 rounded-2xl">
                    <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-2">Hướng dẫn</h4>
                    <p className="text-[10px] text-slate-500 leading-relaxed font-medium">
                      Nhấp vào biểu tượng bút chì trên mỗi thẻ quà để đổi tên hoặc tải lên ảnh mới từ máy tính của bạn.
                    </p>
                 </div>
              </div>

              {/* Right Column: Gift Grid */}
              <div className="lg:col-span-3 space-y-6">
                <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6">
                  {gifts.map((gift) => (
                    <div
                      key={gift.id}
                      className={`relative group p-6 rounded-[2.5rem] border transition-all duration-500 flex flex-col items-center text-center space-y-4 overflow-hidden ${
                        selectedGift?.id === gift.id 
                          ? 'bg-red-600/10 border-red-600 shadow-[0_0_40px_rgba(220,38,38,0.2)]' 
                          : 'bg-white/5 border-white/5 hover:border-white/10'
                      }`}
                    >
                      {/* Edit Button Overlay */}
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          setEditingGiftId(editingGiftId === gift.id ? null : gift.id);
                        }}
                        className="absolute top-4 right-4 p-2 bg-white/10 hover:bg-white/20 rounded-xl text-slate-400 hover:text-white transition-all z-10"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                        </svg>
                      </button>

                      <div 
                        className="cursor-pointer flex flex-col items-center w-full space-y-4"
                        onClick={() => setSelectedGift(gift)}
                      >
                        <div className="w-24 h-24 flex items-center justify-center relative">
                          {gift.image.startsWith('data:') || gift.image.startsWith('http') ? (
                            <img src={gift.image} alt={gift.name} className="w-full h-full object-contain rounded-2xl" />
                          ) : (
                            <span className="text-6xl drop-shadow-2xl">{gift.image}</span>
                          )}
                        </div>

                        {editingGiftId === gift.id ? (
                          <div className="w-full space-y-3 p-2 bg-black/40 rounded-2xl border border-white/5 animate-in fade-in zoom-in duration-300">
                             <input 
                               type="text" 
                               value={gift.name} 
                               onChange={(e) => updateGiftName(gift.id, e.target.value)}
                               className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-[11px] font-bold text-white outline-none focus:border-red-500"
                               placeholder="Tên món quà"
                             />
                             <input 
                               type="text" 
                               value={gift.amount} 
                               onChange={(e) => updateGiftAmount(gift.id, e.target.value)}
                               className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-[11px] font-bold text-red-500 outline-none focus:border-red-500"
                               placeholder="Giá trị (ví dụ: 1000)"
                             />
                             <button 
                               onClick={() => document.getElementById(`file-${gift.id}`)?.click()}
                               className="w-full py-2 bg-blue-600/20 hover:bg-blue-600/40 text-[10px] font-black text-blue-400 uppercase rounded-lg transition-all"
                             >
                               Thay ảnh đại diện
                             </button>
                             <input 
                               id={`file-${gift.id}`}
                               type="file" 
                               className="hidden" 
                               accept="image/*"
                               onChange={(e) => handleImageUpload(e, gift.id)}
                             />
                          </div>
                        ) : (
                          <div className="space-y-1">
                            <div className="text-sm font-black text-white uppercase tracking-tight">{gift.name}</div>
                            <div className="text-[10px] font-black text-red-500 uppercase tracking-widest">{gift.amount} {gift.type === 'robux' ? 'Robux' : ''}</div>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 'processing' && (
          <div className="flex flex-col items-center justify-center min-h-[500px] space-y-12 animate-in zoom-in duration-500">
            <div className="relative w-64 h-64">
               <div className="absolute inset-0 border-4 border-white/5 rounded-full"></div>
               <svg className="absolute inset-0 w-full h-full -rotate-90">
                  <circle
                    cx="128"
                    cy="128"
                    r="124"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="8"
                    strokeDasharray={779}
                    strokeDashoffset={779 - (779 * progress) / 100}
                    className="text-red-600 transition-all duration-300 ease-out"
                  />
               </svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center space-y-2">
                  <span className="text-6xl font-black text-white">{progress}%</span>
                  <span className="text-[10px] font-black text-red-500 uppercase tracking-widest">Đang tải</span>
               </div>
            </div>
            <div className="text-center space-y-4 max-w-md">
               <h3 className="text-xl font-black text-white uppercase tracking-tighter animate-pulse">{statusText}</h3>
            </div>
          </div>
        )}

        {step === 'success' && (
          <div className="flex flex-col items-center justify-center min-h-[500px] space-y-8 animate-in zoom-in duration-700">
            <div className="w-32 h-32 bg-green-500 rounded-[2.5rem] flex items-center justify-center text-white shadow-[0_0_50px_rgba(34,197,94,0.3)] rotate-12">
               <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" />
               </svg>
            </div>
            <div className="text-center space-y-6">
              <div className="space-y-2">
                <h2 className="text-4xl font-black text-white italic tracking-tighter uppercase">XÁC MINH CUỐI CÙNG</h2>
                <p className="text-slate-400 font-medium max-w-md mx-auto leading-relaxed">
                  Gói quà đã sẵn sàng để gửi đi! Hãy hoàn tất xác minh người dùng để tránh robot lạm dụng.
                </p>
              </div>
              <div className="p-8 bg-white/5 rounded-[3rem] border border-white/10 space-y-6">
                 <div className="flex items-center gap-5 text-left">
                    <div className="w-16 h-16 bg-white/5 rounded-2xl flex items-center justify-center overflow-hidden">
                       {selectedGift?.image.startsWith('data:') ? (
                         <img src={selectedGift.image} className="w-full h-full object-cover" />
                       ) : (
                         <span className="text-3xl">{selectedGift?.image}</span>
                       )}
                    </div>
                    <div>
                       <div className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Phần quà của {username}</div>
                       <div className="text-lg font-black text-white uppercase">{selectedGift?.name} ({selectedGift?.amount})</div>
                    </div>
                 </div>
                 <button className="w-full py-5 bg-white text-black font-black rounded-2xl hover:bg-slate-200 transition-all uppercase tracking-widest text-xs">
                   XÁC MINH NGAY
                 </button>
              </div>
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default GiftShop;

import React, { useState, useRef, useEffect } from 'react';
import { RobloxGift } from '../types';

const INITIAL_GIFTS: RobloxGift[] = [
  { id: '1', name: 'Gói Cơ Bản', amount: '400', type: 'robux', image: '💰', rarity: 'common' },
  { id: '2', name: 'Gói Phổ Biến', amount: '800', type: 'robux', image: '💎', rarity: 'common' },
  { id: '3', name: 'Gói Cao Cấp', amount: '1700', type: 'robux', image: '👑', rarity: 'rare' },
  { id: '4', name: 'Gói Huyền Thoại', amount: '10000', type: 'robux', image: '🔥', rarity: 'legendary' },
  { id: '5', name: 'Blox Fruit: Leopard', amount: 'Item', type: 'item', image: '🐆', rarity: 'legendary' },
  { id: '6', name: 'PS99: Huge Pet', amount: 'Item', type: 'item', image: '🐱', rarity: 'rare' },
];

const GiftShop: React.FC = () => {
  const [username, setUsername] = useState('');
  const [gifts, setGifts] = useState<RobloxGift[]>(INITIAL_GIFTS);
  const [selectedGift, setSelectedGift] = useState<RobloxGift | null>(null);
  const [step, setStep] = useState<'form' | 'processing' | 'success'>('form');
  const [progress, setProgress] = useState(0);
  const [statusText, setStatusText] = useState('');
  const [editingGiftId, setEditingGiftId] = useState<string | null>(null);

  // Khôi phục dữ liệu từ LocalStorage khi component mount
  useEffect(() => {
    const savedGifts = localStorage.getItem('roblox_gifts_data');
    if (savedGifts) {
      try {
        setGifts(JSON.parse(savedGifts));
      } catch (e) {
        console.error("Failed to load gifts from storage", e);
      }
    }
  }, []);

  // Lưu dữ liệu vào LocalStorage mỗi khi gifts thay đổi
  const saveGiftsToStorage = (updatedGifts: RobloxGift[]) => {
    setGifts(updatedGifts);
    localStorage.setItem('roblox_gifts_data', JSON.stringify(updatedGifts));
  };

  const handleClaim = () => {
    if (!username || !selectedGift) return;

    setStep('processing');
    setProgress(0);
    const steps = [
      "Đang kết nối tới máy chủ Roblox...",
      `Tìm kiếm người dùng: ${username}...`,
      "Đã tìm thấy tài khoản! Đang kiểm tra vùng dữ liệu...",
      `Đang chuẩn bị phần quà: ${selectedGift.name}...`,
      "Đang thực hiện mã hóa bảo mật (SSL)...",
      "Đang hoàn tất quá trình chuyển đổi...",
      "Thành công! Chờ xác minh cuối cùng."
    ];

    let currentStep = 0;
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setStep('success');
          return 100;
        }

        if (prev % 15 === 0 && currentStep < steps.length) {
            setStatusText(steps[currentStep]);
            currentStep++;
        }
        return prev + 1;
      });
    }, 50);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, giftId: string) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const updated = gifts.map(g => 
          g.id === giftId ? { ...g, image: reader.result as string } : g
        );
        saveGiftsToStorage(updated);
      };
      reader.readAsDataURL(file);
    }
  };

  const updateGiftName = (id: string, newName: string) => {
    const updated = gifts.map(g => g.id === id ? { ...g, name: newName } : g);
    saveGiftsToStorage(updated);
  };

  const updateGiftAmount = (id: string, newAmount: string) => {
    const updated = gifts.map(g => g.id === id ? { ...g, amount: newAmount } : g);
    saveGiftsToStorage(updated);
  };

  const resetToStore = () => {
    setStep('form');
    setProgress(0);
  };

  return (
    <div className="h-full overflow-y-auto p-8 scrollbar-hide">
      <div className="max-w-6xl mx-auto space-y-12 pb-24">

        {step === 'form' && (
          <div className="animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="text-center space-y-4 mb-12">
               <h2 className="text-5xl font-black text-white italic tracking-tighter uppercase">KHO QUÀ TÙY CHỈNH</h2>
               <p className="text-slate-500 font-bold uppercase tracking-[0.3em] text-xs">Cấu hình quà tặng và nhận ngay Robux</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-10">
              <div className="lg:col-span-1 space-y-6">
                 <div className="p-6 bg-white/5 rounded-[2rem] border border-white/10 space-y-6 shadow-2xl">
                    <label className="text-[10px] font-black text-red-500 uppercase tracking-widest">Tài khoản nhận quà</label>
                    <div className="relative">
                       <input 
                         type="text"
                         value={username}
                         onChange={(e) => setUsername(e.target.value)}
                         placeholder="Roblox Username"
                         className="w-full bg-[#0a0a0c] border border-white/10 rounded-xl px-4 py-4 text-white font-bold focus:border-red-600 outline-none transition-all placeholder:text-slate-700 text-sm"
                       />
                    </div>
                 </div>

                 <button 
                   onClick={handleClaim}
                   disabled={!username || !selectedGift}
                   className="w-full py-5 bg-gradient-to-r from-red-600 to-orange-600 hover:from-red-500 hover:to-orange-500 disabled:from-slate-800 disabled:to-slate-800 disabled:opacity-50 text-white font-black rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xs"
                 >
                   XÁC NHẬN NHẬN QUÀ
                 </button>

                 <div className="p-5 bg-blue-500/5 border border-blue-500/10 rounded-2xl">
                    <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-2">Hướng dẫn</h4>
                    <p className="text-[10px] text-slate-500 leading-relaxed font-medium">
                      Dữ liệu quà tặng đã được lưu tự động. Bạn có thể chuyển tab thoải mái mà không lo mất ảnh đã tải lên.
                    </p>
                    <button 
                      onClick={() => { if(confirm("Bạn có chắc muốn khôi phục kho quà về mặc định?")) { localStorage.removeItem('roblox_gifts_data'); setGifts(INITIAL_GIFTS); } }}
                      className="mt-4 text-[9px] text-red-500/50 hover:text-red-500 font-bold uppercase transition-colors"
                    >
                      Xóa dữ liệu & Khôi phục
                    </button>
                 </div>
              </div>

              <div className="lg:col-span-3 space-y-6">
                <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6">
                  {gifts.map((gift) => (
                    <div
                      key={gift.id}
                      className={`relative group p-6 rounded-[2.5rem] border transition-all duration-500 flex flex-col items-center text-center space-y-4 overflow-hidden ${
                        selectedGift?.id === gift.id 
                          ? 'bg-red-600/10 border-red-600 shadow-[0_0_40px_rgba(220,38,38,0.2)]' 
                          : 'bg-white/5 border-white/5 hover:border-white/10'
                      }`}
                    >
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          setEditingGiftId(editingGiftId === gift.id ? null : gift.id);
                        }}
                        className="absolute top-4 right-4 p-2 bg-white/10 hover:bg-white/20 rounded-xl text-slate-400 hover:text-white transition-all z-10"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                        </svg>
                      </button>

                      <div 
                        className="cursor-pointer flex flex-col items-center w-full space-y-4"
                        onClick={() => setSelectedGift(gift)}
                      >
                        <div className="w-24 h-24 flex items-center justify-center relative">
                          {gift.image.startsWith('data:') || gift.image.startsWith('http') ? (
                            <img src={gift.image} alt={gift.name} className="w-full h-full object-contain rounded-2xl" />
                          ) : (
                            <span className="text-6xl drop-shadow-2xl">{gift.image}</span>
                          )}
                        </div>

                        {editingGiftId === gift.id ? (
                          <div className="w-full space-y-3 p-2 bg-black/40 rounded-2xl border border-white/5 animate-in fade-in zoom-in duration-300">
                             <input 
                               type="text" 
                               value={gift.name} 
                               onChange={(e) => updateGiftName(gift.id, e.target.value)}
                               className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-[11px] font-bold text-white outline-none focus:border-red-500"
                               placeholder="Tên món quà"
                               onClick={(e) => e.stopPropagation()}
                             />
                             <input 
                               type="text" 
                               value={gift.amount} 
                               onChange={(e) => updateGiftAmount(gift.id, e.target.value)}
                               className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-[11px] font-bold text-red-500 outline-none focus:border-red-500"
                               placeholder="Giá trị"
                               onClick={(e) => e.stopPropagation()}
                             />
                             <button 
                               onClick={(e) => { e.stopPropagation(); document.getElementById(`file-${gift.id}`)?.click(); }}
                               className="w-full py-2 bg-blue-600/20 hover:bg-blue-600/40 text-[10px] font-black text-blue-400 uppercase rounded-lg transition-all"
                             >
                               Thay ảnh đại diện
                             </button>
                             <input 
                               id={`file-${gift.id}`}
                               type="file" 
                               className="hidden" 
                               accept="image/*"
                               onChange={(e) => handleImageUpload(e, gift.id)}
                             />
                          </div>
                        ) : (
                          <div className="space-y-1">
                            <div className="text-sm font-black text-white uppercase tracking-tight">{gift.name}</div>
                            <div className="text-[10px] font-black text-red-500 uppercase tracking-widest">{gift.amount} {gift.type === 'robux' ? 'Robux' : ''}</div>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 'processing' && (
          <div className="flex flex-col items-center justify-center min-h-[500px] space-y-12 animate-in zoom-in duration-500">
            <div className="relative w-64 h-64">
               <div className="absolute inset-0 border-4 border-white/5 rounded-full"></div>
               <svg className="absolute inset-0 w-full h-full -rotate-90">
                  <circle
                    cx="128"
                    cy="128"
                    r="124"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="8"
                    strokeDasharray={779}
                    strokeDashoffset={779 - (779 * progress) / 100}
                    className="text-red-600 transition-all duration-300 ease-out"
                  />
               </svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center space-y-2">
                  <span className="text-6xl font-black text-white">{progress}%</span>
                  <span className="text-[10px] font-black text-red-500 uppercase tracking-widest">Đang tải</span>
               </div>
            </div>
            <div className="text-center space-y-4 max-w-md">
               <h3 className="text-xl font-black text-white uppercase tracking-tighter animate-pulse">{statusText}</h3>
            </div>
          </div>
        )}

        {step === 'success' && (
          <div className="flex flex-col items-center justify-center min-h-[500px] space-y-8 animate-in zoom-in duration-700 text-center">
            <div className="w-32 h-32 bg-green-500 rounded-[2.5rem] flex items-center justify-center text-white shadow-[0_0_50px_rgba(34,197,94,0.3)] rotate-12">
               <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" />
               </svg>
            </div>
            <div className="space-y-6 w-full max-w-lg">
              <div className="space-y-2">
                <h2 className="text-4xl font-black text-white italic tracking-tighter uppercase">XÁC MINH CUỐI CÙNG</h2>
                <p className="text-slate-400 font-medium leading-relaxed">
                  Gói quà đã sẵn sàng! Hãy hoàn tất bước này để gửi trực tiếp vào tài khoản <strong>{username}</strong>.
                </p>
              </div>
              <div className="p-8 bg-white/5 rounded-[3rem] border border-white/10 space-y-6">
                 <div className="flex items-center gap-5 text-left">
                    <div className="w-16 h-16 bg-white/5 rounded-2xl flex items-center justify-center overflow-hidden flex-shrink-0">
                       {selectedGift?.image.startsWith('data:') ? (
                         <img src={selectedGift.image} className="w-full h-full object-cover" />
                       ) : (
                         <span className="text-3xl">{selectedGift?.image}</span>
                       )}
                    </div>
                    <div>
                       <div className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Gói quà đã chọn</div>
                       <div className="text-lg font-black text-white uppercase line-clamp-1">{selectedGift?.name}</div>
                       <div className="text-xs font-bold text-red-500">{selectedGift?.amount} {selectedGift?.type === 'robux' ? 'Robux' : ''}</div>
                    </div>
                 </div>
                 <button className="w-full py-5 bg-white text-black font-black rounded-2xl hover:bg-slate-200 transition-all uppercase tracking-widest text-xs">
                   XÁC MINH NGAY
                 </button>
              </div>

              <button 
                onClick={resetToStore}
                className="text-[10px] font-black text-slate-500 hover:text-white uppercase tracking-[0.2em] transition-all flex items-center gap-2 mx-auto"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                </svg>
                Quay lại kho quà tặng
              </button>
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default GiftShop;
